// Extrai JSON da resposta do Claude e funde com contexto recebido do caller.
const resposta = $input.first().json.content[0].text;
const inicio = resposta.indexOf('{');
const fim = resposta.lastIndexOf('}') + 1;
const acao = JSON.parse(resposta.substring(inicio, fim));

const contexto = $('Execute Workflow Trigger').first().json;

return [{
  json: {
    ...acao,
    grupo: contexto.grupo,
    remote_jid: contexto.remote_jid,
    remetente: contexto.remetente,
    timestamp: contexto.timestamp
  }
}];
